import crypto from 'crypto';

import jwt from 'jsonwebtoken';

import { env } from './env';

export function signAccessToken(userId: string, role: string): string {
  return jwt.sign({ sub: userId, role }, env.JWT_SECRET, {
    expiresIn: env.JWT_EXPIRES_IN,
  });
}

export function signRefreshToken(): string {
  return crypto.randomUUID();
}

export function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

export function generateOtp(): string {
  return crypto.randomInt(100000, 999999).toString();
}

export function generateVerificationToken(): string {
  return crypto.randomUUID();
}

export function getRefreshTokenExpiry(): Date {
  const ms = parseDuration(env.JWT_REFRESH_EXPIRES_IN);
  return new Date(Date.now() + ms);
}

function parseDuration(dur: string): number {
  const match = dur.match(/^(\d+)([smhd])$/);
  if (!match) return 7 * 24 * 60 * 60 * 1000;
  const val = parseInt(match[1], 10);
  switch (match[2]) {
    case 's': return val * 1000;
    case 'm': return val * 60 * 1000;
    case 'h': return val * 60 * 60 * 1000;
    case 'd': return val * 24 * 60 * 60 * 1000;
    default: return 7 * 24 * 60 * 60 * 1000;
  }
}

import { Resend } from 'resend';

import { env } from './env';
import { logger } from './logger';

const resend = env.RESEND_API_KEY ? new Resend(env.RESEND_API_KEY) : null;

const FROM_EMAIL = 'Roamera <noreply@roamera.in>';
const APP_URL = env.NODE_ENV === 'production'
  ? 'https://roamera.in'
  : 'http://localhost:3001';

async function sendEmail(to: string, subject: string, html: string): Promise<void> {
  if (!resend) {
    logger.info({ to, subject, html }, '[DEV EMAIL] Would send email:');
    return;
  }

  await resend.emails.send({
    from: FROM_EMAIL,
    to,
    subject,
    html,
  });
}

export async function sendVerificationEmail(to: string, token: string): Promise<void> {
  const link = `${APP_URL}/verify-email?token=${token}`;
  await sendEmail(
    to,
    'Verify your Roamera email',
    `<h2>Welcome to Roamera!</h2>
     <p>Click the link below to verify your email address:</p>
     <p><a href="${link}">${link}</a></p>
     <p>This link expires in 24 hours.</p>`,
  );
}

export async function sendOtpEmail(to: string, code: string): Promise<void> {
  await sendEmail(
    to,
    'Your Roamera login code',
    `<h2>Your login code</h2>
     <p style="font-size: 32px; font-weight: bold; letter-spacing: 4px;">${code}</p>
     <p>This code expires in 10 minutes. Do not share it with anyone.</p>`,
  );
}

export async function sendPasswordResetEmail(to: string, token: string): Promise<void> {
  const link = `${APP_URL}/reset-password?token=${token}`;
  await sendEmail(
    to,
    'Reset your Roamera password',
    `<h2>Password Reset</h2>
     <p>Click the link below to reset your password:</p>
     <p><a href="${link}">${link}</a></p>
     <p>This link expires in 1 hour. If you didn't request this, ignore this email.</p>`,
  );
}

import rateLimit from 'express-rate-limit';

export const authRateLimit = rateLimit({
  windowMs: 60 * 1000,
  max: 5,
  standardHeaders: true,
  legacyHeaders: false,
  message: { success: false, error: 'Too many attempts, please try again later.' },
});

export const uploadRateLimit = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  standardHeaders: true,
  legacyHeaders: false,
  message: { success: false, error: 'Too many uploads, please try again later.' },
});

import { Router } from 'express';
import bcrypt from 'bcryptjs';
import { eq, and, isNull, gt } from 'drizzle-orm';

import {
  RegisterSchema,
  LoginSchema,
  OtpSendSchema,
  OtpVerifySchema,
  RefreshSchema,
  PasswordResetRequestSchema,
  PasswordResetSchema,
  PasswordChangeSchema,
} from '@roamera/types';

import { db } from '../db/client';
import { users, sessions, otpTokens, passwordResetTokens, follows, posts } from '../db/schema';
import { sendVerificationEmail, sendOtpEmail, sendPasswordResetEmail } from '../lib/email';
import {
  signAccessToken,
  signRefreshToken,
  hashToken,
  generateOtp,
  generateVerificationToken,
  getRefreshTokenExpiry,
} from '../lib/tokens';
import { authenticate, type AuthRequest } from '../middleware/auth';
import { authRateLimit } from '../middleware/rate-limit';
import { AppError } from '../middleware/error';

const router = Router();

// In-memory ws_token store (lightweight, no DB needed)
const wsTokenStore = new Map<string, { userId: string; expiresAt: number }>();

function formatUserResponse(user: typeof users.$inferSelect, extra?: {
  followersCount?: number;
  followingCount?: number;
  postsCount?: number;
  isFollowing?: boolean;
}) {
  return {
    id: user.id,
    username: user.username,
    email: user.email,
    bio: user.bio,
    homeCity: user.homeCity,
    avatarUrl: user.avatarKey ? `/uploads/${user.avatarKey}` : null,
    budgetBand: user.budgetBand,
    interests: user.interests,
    role: user.role,
    emailVerified: user.emailVerified,
    followersCount: extra?.followersCount ?? 0,
    followingCount: extra?.followingCount ?? 0,
    postsCount: extra?.postsCount ?? 0,
    isFollowing: extra?.isFollowing,
    createdAt: user.createdAt instanceof Date ? user.createdAt.toISOString() : new Date(Number(user.createdAt) * 1000).toISOString(),
  };
}

async function getUserCounts(userId: string) {
  const [followersResult] = await db.select({ count: follows.followerId })
    .from(follows).where(eq(follows.followingId, userId));
  const [followingResult] = await db.select({ count: follows.followingId })
    .from(follows).where(eq(follows.followerId, userId));
  const [postsResult] = await db.select({ count: posts.id })
    .from(posts).where(eq(posts.userId, userId));

  const followersCount = followersResult ? await db.select().from(follows).where(eq(follows.followingId, userId)).then(r => r.length) : 0;
  const followingCount = followingResult ? await db.select().from(follows).where(eq(follows.followerId, userId)).then(r => r.length) : 0;
  const postsCount = postsResult ? await db.select().from(posts).where(eq(posts.userId, userId)).then(r => r.length) : 0;

  return { followersCount, followingCount, postsCount };
}

// POST /register
router.post('/register', authRateLimit, async (req, res, next) => {
  try {
    const body = RegisterSchema.parse(req.body);

    const existingEmail = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.email, body.email),
    });
    if (existingEmail) throw new AppError('Email already in use', 409, 'EMAIL_EXISTS');

    const existingUsername = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.username, body.username),
    });
    if (existingUsername) throw new AppError('Username already taken', 409, 'USERNAME_EXISTS');

    const passwordHash = await bcrypt.hash(body.password, 12);

    const [user] = await db.insert(users).values({
      username: body.username,
      email: body.email,
      passwordHash,
    }).returning();

    const token = generateVerificationToken();
    const tokenHash = hashToken(token);
    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000);

    await db.insert(passwordResetTokens).values({
      userId: user.id,
      tokenHash,
      expiresAt,
    });

    await sendVerificationEmail(body.email, token);

    res.status(201).json({
      success: true,
      message: 'Account created. Please check your email to verify your address.',
    });
  } catch (err) {
    next(err);
  }
});

// GET /verify-email?token=
router.get('/verify-email', async (req, res, next) => {
  try {
    const token = req.query.token as string;
    if (!token) throw new AppError('Token is required', 400);

    const tokenHash = hashToken(token);

    const resetToken = await db.query.passwordResetTokens.findFirst({
      where: (t, { eq: e, and: a, isNull: n, gt: g }) =>
        a(e(t.tokenHash, tokenHash), n(t.usedAt), g(t.expiresAt, new Date())),
    });

    if (!resetToken) throw new AppError('Invalid or expired verification link', 400);

    await db.update(users)
      .set({ emailVerified: true, updatedAt: new Date() })
      .where(eq(users.id, resetToken.userId));

    await db.update(passwordResetTokens)
      .set({ usedAt: new Date() })
      .where(eq(passwordResetTokens.id, resetToken.id));

    res.json({ success: true, message: 'Email verified successfully.' });
  } catch (err) {
    next(err);
  }
});

// POST /login
router.post('/login', authRateLimit, async (req, res, next) => {
  try {
    const body = LoginSchema.parse(req.body);

    const user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.email, body.email),
    });
    if (!user || !user.passwordHash) throw new AppError('Invalid email or password', 401);
    if (user.role === 'deleted' as string) throw new AppError('Account has been deleted', 401);

    const valid = await bcrypt.compare(body.password, user.passwordHash);
    if (!valid) throw new AppError('Invalid email or password', 401);

    if (!user.emailVerified) {
      throw new AppError('Please verify your email before logging in', 403, 'EMAIL_NOT_VERIFIED');
    }

    const accessToken = signAccessToken(user.id, user.role);
    const refreshToken = signRefreshToken();
    const tokenHash = hashToken(refreshToken);
    const expiresAt = getRefreshTokenExpiry();

    await db.insert(sessions).values({
      userId: user.id,
      tokenHash,
      expiresAt,
    });

    const counts = await getUserCounts(user.id);

    res.json({
      success: true,
      accessToken,
      refreshToken,
      user: formatUserResponse(user, counts),
    });
  } catch (err) {
    next(err);
  }
});

// POST /otp/send
router.post('/otp/send', authRateLimit, async (req, res, next) => {
  try {
    const body = OtpSendSchema.parse(req.body);
    const code = generateOtp();
    const codeHash = await bcrypt.hash(code, 10);
    const expiresAt = new Date(Date.now() + 10 * 60 * 1000);

    await db.insert(otpTokens).values({
      email: body.email,
      codeHash,
      expiresAt,
    });

    await sendOtpEmail(body.email, code);

    res.json({ success: true, message: 'OTP sent to your email.' });
  } catch (err) {
    next(err);
  }
});

// POST /otp/verify
router.post('/otp/verify', async (req, res, next) => {
  try {
    const body = OtpVerifySchema.parse(req.body);

    const otpRecords = await db.select()
      .from(otpTokens)
      .where(
        and(
          eq(otpTokens.email, body.email),
          isNull(otpTokens.usedAt),
          gt(otpTokens.expiresAt, new Date()),
        ),
      )
      .orderBy(otpTokens.createdAt)
      .limit(5);

    let validOtp: typeof otpRecords[0] | null = null;
    for (const otp of otpRecords) {
      const match = await bcrypt.compare(body.code, otp.codeHash);
      if (match) {
        validOtp = otp;
        break;
      }
    }

    if (!validOtp) throw new AppError('Invalid or expired OTP', 401);

    await db.update(otpTokens)
      .set({ usedAt: new Date() })
      .where(eq(otpTokens.id, validOtp.id));

    let user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.email, body.email),
    });

    if (!user) {
      const username = body.email.split('@')[0].replace(/[^a-zA-Z0-9_]/g, '_').slice(0, 30);
      const [newUser] = await db.insert(users).values({
        email: body.email,
        username: `${username}_${Date.now().toString(36)}`.slice(0, 30),
        emailVerified: true,
      }).returning();
      user = newUser;
    } else if (!user.emailVerified) {
      await db.update(users)
        .set({ emailVerified: true, updatedAt: new Date() })
        .where(eq(users.id, user.id));
      user = { ...user, emailVerified: true };
    }

    const accessToken = signAccessToken(user.id, user.role);
    const refreshToken = signRefreshToken();
    const tokenHash = hashToken(refreshToken);
    const expiresAt = getRefreshTokenExpiry();

    await db.insert(sessions).values({
      userId: user.id,
      tokenHash,
      expiresAt,
    });

    const counts = await getUserCounts(user.id);

    res.json({
      success: true,
      accessToken,
      refreshToken,
      user: formatUserResponse(user, counts),
    });
  } catch (err) {
    next(err);
  }
});

// POST /refresh
router.post('/refresh', async (req, res, next) => {
  try {
    const body = RefreshSchema.parse(req.body);
    const tokenHash = hashToken(body.refreshToken);

    const session = await db.query.sessions.findFirst({
      where: (t, { eq: e, and: a, gt: g }) =>
        a(e(t.tokenHash, tokenHash), g(t.expiresAt, new Date())),
    });

    if (!session) throw new AppError('Invalid or expired refresh token', 401);

    await db.delete(sessions).where(eq(sessions.id, session.id));

    const user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.id, session.userId),
    });
    if (!user) throw new AppError('User not found', 401);

    const accessToken = signAccessToken(user.id, user.role);
    const newRefreshToken = signRefreshToken();
    const newTokenHash = hashToken(newRefreshToken);
    const expiresAt = getRefreshTokenExpiry();

    await db.insert(sessions).values({
      userId: user.id,
      tokenHash: newTokenHash,
      expiresAt,
    });

    const counts = await getUserCounts(user.id);

    res.json({
      success: true,
      accessToken,
      refreshToken: newRefreshToken,
      user: formatUserResponse(user, counts),
    });
  } catch (err) {
    next(err);
  }
});

// POST /logout
router.post('/logout', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const header = req.headers.authorization;
    if (!header) throw new AppError('Not authenticated', 401);

    await db.delete(sessions).where(eq(sessions.userId, req.user!.id));

    res.json({ success: true, message: 'Logged out successfully.' });
  } catch (err) {
    next(err);
  }
});

// POST /password/reset-request
router.post('/password/reset-request', authRateLimit, async (req, res, next) => {
  try {
    const body = PasswordResetRequestSchema.parse(req.body);

    const user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.email, body.email),
    });

    // Always return success to prevent email enumeration
    if (!user) {
      res.json({ success: true, message: 'If an account exists, a reset link has been sent.' });
      return;
    }

    const token = generateVerificationToken();
    const tokenHash = hashToken(token);
    const expiresAt = new Date(Date.now() + 60 * 60 * 1000);

    await db.insert(passwordResetTokens).values({
      userId: user.id,
      tokenHash,
      expiresAt,
    });

    await sendPasswordResetEmail(body.email, token);

    res.json({ success: true, message: 'If an account exists, a reset link has been sent.' });
  } catch (err) {
    next(err);
  }
});

// POST /password/reset
router.post('/password/reset', async (req, res, next) => {
  try {
    const body = PasswordResetSchema.parse(req.body);
    const tokenHash = hashToken(body.token);

    const resetToken = await db.query.passwordResetTokens.findFirst({
      where: (t, { eq: e, and: a, isNull: n, gt: g }) =>
        a(e(t.tokenHash, tokenHash), n(t.usedAt), g(t.expiresAt, new Date())),
    });

    if (!resetToken) throw new AppError('Invalid or expired reset token', 400);

    const passwordHash = await bcrypt.hash(body.password, 12);

    await db.update(users)
      .set({ passwordHash, updatedAt: new Date() })
      .where(eq(users.id, resetToken.userId));

    await db.update(passwordResetTokens)
      .set({ usedAt: new Date() })
      .where(eq(passwordResetTokens.id, resetToken.id));

    // Invalidate all sessions
    await db.delete(sessions).where(eq(sessions.userId, resetToken.userId));

    res.json({ success: true, message: 'Password reset successfully. Please log in.' });
  } catch (err) {
    next(err);
  }
});

// POST /password/change
router.post('/password/change', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const body = PasswordChangeSchema.parse(req.body);
    const userId = req.user!.id;

    const user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.id, userId),
    });
    if (!user || !user.passwordHash) throw new AppError('User not found', 404);

    const valid = await bcrypt.compare(body.currentPassword, user.passwordHash);
    if (!valid) throw new AppError('Current password is incorrect', 401);

    const passwordHash = await bcrypt.hash(body.newPassword, 12);

    await db.update(users)
      .set({ passwordHash, updatedAt: new Date() })
      .where(eq(users.id, userId));

    // Invalidate other sessions (keep the current one implied via access token)
    await db.delete(sessions).where(eq(sessions.userId, userId));

    res.json({ success: true, message: 'Password changed successfully.' });
  } catch (err) {
    next(err);
  }
});

// GET /me
router.get('/me', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const user = await db.query.users.findFirst({
      where: (t, { eq: e }) => e(t.id, req.user!.id),
    });
    if (!user) throw new AppError('User not found', 404);

    const counts = await getUserCounts(user.id);

    res.json({ success: true, user: formatUserResponse(user, counts) });
  } catch (err) {
    next(err);
  }
});

// GET /ws-token
router.get('/ws-token', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const token = generateVerificationToken();
    const expiresAt = Date.now() + 10 * 60 * 1000;

    wsTokenStore.set(token, { userId: req.user!.id, expiresAt });

    // Clean up expired tokens periodically
    for (const [key, value] of wsTokenStore) {
      if (value.expiresAt < Date.now()) wsTokenStore.delete(key);
    }

    res.json({ success: true, token });
  } catch (err) {
    next(err);
  }
});

export { wsTokenStore };
export default router;

import crypto from 'crypto';
import fs from 'fs/promises';
import path from 'path';

import { S3Client, PutObjectCommand, DeleteObjectCommand } from '@aws-sdk/client-s3';

import { env } from './env';

const UPLOAD_DIR = path.resolve(process.cwd(), 'data/uploads');

let s3Client: S3Client | null = null;

function getS3Client(): S3Client {
  if (!s3Client) {
    s3Client = new S3Client({
      region: 'auto',
      endpoint: `https://${env.R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
      credentials: {
        accessKeyId: env.R2_ACCESS_KEY_ID!,
        secretAccessKey: env.R2_SECRET_ACCESS_KEY!,
      },
    });
  }
  return s3Client;
}

export function generateStorageKey(buffer: Buffer, ext: string): string {
  const hash = crypto.createHash('sha256').update(buffer).digest('hex').slice(0, 16);
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  return `${year}/${month}/${hash}${ext}`;
}

export async function uploadFile(buffer: Buffer, key: string, mimeType: string): Promise<void> {
  if (env.STORAGE_DRIVER === 'local') {
    const filePath = path.join(UPLOAD_DIR, key);
    await fs.mkdir(path.dirname(filePath), { recursive: true });
    await fs.writeFile(filePath, buffer);
  } else {
    const client = getS3Client();
    await client.send(new PutObjectCommand({
      Bucket: env.R2_BUCKET_NAME!,
      Key: key,
      Body: buffer,
      ContentType: mimeType,
    }));
  }
}

export function getPublicUrl(key: string | null): string | null {
  if (!key) return null;
  if (env.STORAGE_DRIVER === 'local') {
    return `/uploads/${key}`;
  }
  return `https://${env.R2_BUCKET_NAME}.r2.dev/${key}`;
}

export async function deleteFile(key: string): Promise<void> {
  if (env.STORAGE_DRIVER === 'local') {
    const filePath = path.join(UPLOAD_DIR, key);
    await fs.unlink(filePath).catch(() => {});
  } else {
    const client = getS3Client();
    await client.send(new DeleteObjectCommand({
      Bucket: env.R2_BUCKET_NAME!,
      Key: key,
    }));
  }
}

import { Router } from 'express';
import multer from 'multer';
import sharp from 'sharp';
import { eq, and, like, or, sql } from 'drizzle-orm';

import { UpdateProfileSchema, UserSearchParamsSchema } from '@roamera/types';

import { db } from '../db/client';
import { users, follows, posts, userSettings } from '../db/schema';
import { authenticate, type AuthRequest } from '../middleware/auth';
import { uploadRateLimit } from '../middleware/rate-limit';
import { AppError } from '../middleware/error';
import { uploadFile, generateStorageKey, getPublicUrl } from '../lib/storage';

const router = Router();
const upload = multer({ limits: { fileSize: 5 * 1024 * 1024 }, storage: multer.memoryStorage() });

function formatUserResponse(user: typeof users.$inferSelect, extra?: {
  followersCount?: number;
  followingCount?: number;
  postsCount?: number;
  isFollowing?: boolean;
}) {
  return {
    id: user.id,
    username: user.username,
    email: user.email,
    bio: user.bio,
    homeCity: user.homeCity,
    avatarUrl: getPublicUrl(user.avatarKey),
    budgetBand: user.budgetBand,
    interests: user.interests,
    role: user.role,
    emailVerified: user.emailVerified,
    followersCount: extra?.followersCount ?? 0,
    followingCount: extra?.followingCount ?? 0,
    postsCount: extra?.postsCount ?? 0,
    isFollowing: extra?.isFollowing,
    createdAt: user.createdAt instanceof Date ? user.createdAt.toISOString() : new Date(Number(user.createdAt) * 1000).toISOString(),
  };
}

async function getUserCounts(userId: string) {
  const followersRows = await db.select().from(follows).where(eq(follows.followingId, userId));
  const followingRows = await db.select().from(follows).where(eq(follows.followerId, userId));
  const postsRows = await db.select().from(posts).where(eq(posts.userId, userId));
  return {
    followersCount: followersRows.length,
    followingCount: followingRows.length,
    postsCount: postsRows.length,
  };
}

// GET /search — must be before /:username to avoid conflict
router.get('/search', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const params = UserSearchParamsSchema.parse(req.query);
    const pattern = `%${params.q}%`;

    const results = await db.select()
      .from(users)
      .where(or(
        like(users.username, pattern),
        like(users.bio, pattern),
      ))
      .limit(params.limit);

    const formatted = await Promise.all(results.map(async (u) => {
      const counts = await getUserCounts(u.id);
      return formatUserResponse(u, counts);
    }));

    res.json({ success: true, users: formatted });
  } catch (err) {
    next(err);
  }
});

// GET /me/settings
router.get('/me/settings', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const settings = await db.select()
      .from(userSettings)
      .where(eq(userSettings.userId, req.user!.id));

    const result: Record<string, string> = {};
    for (const s of settings) {
      result[s.key] = s.value;
    }

    res.json({ success: true, settings: result });
  } catch (err) {
    next(err);
  }
});

// PUT /me/settings
router.put('/me/settings', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const body = req.body as Record<string, string>;
    const userId = req.user!.id;

    for (const [key, value] of Object.entries(body)) {
      if (typeof key !== 'string' || typeof value !== 'string') continue;
      await db.insert(userSettings)
        .values({ userId, key, value })
        .onConflictDoUpdate({
          target: [userSettings.userId, userSettings.key],
          set: { value, updatedAt: new Date() },
        });
    }

