    setDeleting(true);
    try {
      await getApiClient().delete('/api/v1/users/me');
      toast.success('Account scheduled for deletion');
      logout();
      router.push('/login');
    } catch (err: any) {
      toast.error(err.response?.data?.error ?? 'Failed to delete account');
    } finally {
      setDeleting(false);
    }
