            {errors.currentPassword && <p className="text-sm text-red-500 mt-1">{errors.currentPassword.message}</p>}
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">New Password</label>
            <input
              type="password"
              {...register('newPassword')}
              className="w-full px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-primary-500 focus:border-transparent outline-none transition"
            />
            {errors.newPassword && <p className="text-sm text-red-500 mt-1">{errors.newPassword.message}</p>}
          </div>
          <button
            type="submit"
            disabled={changingPassword}
            className="px-6 py-2.5 bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl transition disabled:opacity-50 flex items-center gap-2"
          >
            {changingPassword && <Loader2 className="h-4 w-4 animate-spin" />}
            Change password
          </button>
        </form>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl p-8 shadow-card border border-red-200 dark:border-red-900">
        <div className="flex items-start gap-3">
          <AlertTriangle className="h-5 w-5 text-red-500 mt-0.5 flex-shrink-0" />
          <div>
            <h2 className="text-lg font-semibold text-red-600">Danger Zone</h2>
            <p className="text-sm text-slate-600 dark:text-slate-400 mt-1 mb-4">
              Once you delete your account, you have 30 days to contact support to restore it.
              After that, all your data will be permanently removed.
            </p>
            <button
              onClick={handleDeleteAccount}
              disabled={deleting}
              className="px-6 py-2.5 bg-red-600 hover:bg-red-700 text-white font-medium rounded-xl transition disabled:opacity-50 flex items-center gap-2"
            >
              {deleting && <Loader2 className="h-4 w-4 animate-spin" />}
              Delete my account
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import * as SecureStore from 'expo-secure-store';
import { create } from 'zustand';
import { configureClient, getApiClient } from '@roamera/sdk';
import type { User } from '@roamera/types';

const ACCESS_TOKEN_KEY = 'roamera_access_token';
const REFRESH_TOKEN_KEY = 'roamera_refresh_token';

export async function getStoredToken(): Promise<string | null> {
  return SecureStore.getItemAsync(ACCESS_TOKEN_KEY);
}

export async function getStoredRefreshToken(): Promise<string | null> {
  return SecureStore.getItemAsync(REFRESH_TOKEN_KEY);
}

export async function setStoredTokens(accessToken: string, refreshToken: string): Promise<void> {
  await SecureStore.setItemAsync(ACCESS_TOKEN_KEY, accessToken);
  await SecureStore.setItemAsync(REFRESH_TOKEN_KEY, refreshToken);
}

export async function clearStoredTokens(): Promise<void> {
  await SecureStore.deleteItemAsync(ACCESS_TOKEN_KEY);
  await SecureStore.deleteItemAsync(REFRESH_TOKEN_KEY);
}

interface AuthState {
  accessToken: string | null;
  refreshToken: string | null;
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (accessToken: string, refreshToken: string, user: User) => void;
  logout: () => void;
  setUser: (user: User) => void;
  initialize: () => Promise<void>;
}

export const useAuthStore = create<AuthState>((set, get) => ({
  accessToken: null,
  refreshToken: null,
  user: null,
  isAuthenticated: false,
  isLoading: true,

  login: (accessToken, refreshToken, user) => {
    void setStoredTokens(accessToken, refreshToken);
    set({ accessToken, refreshToken, user, isAuthenticated: true });
  },

  logout: () => {
    void clearStoredTokens();
    set({ accessToken: null, refreshToken: null, user: null, isAuthenticated: false });
  },

  setUser: (user) => set({ user }),

  initialize: async () => {
    const accessToken = await getStoredToken();
    const refreshToken = await getStoredRefreshToken();

    if (!accessToken || !refreshToken) {
      set({ isLoading: false });
      return;
    }

    set({ accessToken, refreshToken, isAuthenticated: true });

    try {
      const { data } = await getApiClient().get('/api/v1/auth/me');
      set({ user: data.user, isLoading: false });
    } catch {
      try {
        const { data } = await getApiClient().post('/api/v1/auth/refresh', { refreshToken });
        await setStoredTokens(data.accessToken, data.refreshToken);
        set({
          accessToken: data.accessToken,
          refreshToken: data.refreshToken,
          user: data.user,
          isLoading: false,
        });
      } catch {
        get().logout();
        set({ isLoading: false });
      }
    }
  },
}));

export function setupMobileAuthClient() {
  configureClient({
    tokenGetter: () => useAuthStore.getState().accessToken,
    tokenSetter: (token) => {
      if (token) {
        const refresh = useAuthStore.getState().refreshToken;
        if (refresh) void setStoredTokens(token, refresh);
        useAuthStore.setState({ accessToken: token });
      } else {
        useAuthStore.getState().logout();
      }
    },
    refreshFn: async () => {
      const refreshToken = useAuthStore.getState().refreshToken;
      if (!refreshToken) return null;
      try {
        const { data } = await getApiClient().post('/api/v1/auth/refresh', { refreshToken });
        await setStoredTokens(data.accessToken, data.refreshToken);
        useAuthStore.setState({ refreshToken: data.refreshToken, user: data.user });
        return data.accessToken;
      } catch {
        useAuthStore.getState().logout();
        return null;
      }
    },
  });
}

