import { useState } from 'react';
import {
  Text,
  View,
  TextInput,
  TouchableOpacity,
  ActivityIndicator,
  Alert,
  KeyboardAvoidingView,
  Platform,
} from 'react-native';
import { useRouter, Link } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { getApiClient } from '@roamera/sdk';
import { useAuthStore } from '../../lib/auth';

export default function OtpScreen() {
  const router = useRouter();
  const login = useAuthStore((s) => s.login);
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [step, setStep] = useState<'email' | 'code'>('email');
  const [loading, setLoading] = useState(false);

  const handleSendOtp = async () => {
    if (!email) { Alert.alert('Error', 'Enter your email'); return; }
    setLoading(true);
    try {
      await getApiClient().post('/api/v1/auth/otp/send', { email });
      setStep('code');
    } catch (err: any) {
      Alert.alert('Error', err.response?.data?.error ?? 'Failed to send OTP');
    } finally {
      setLoading(false);
    }
  };

  const handleVerify = async () => {
    if (code.length !== 6) { Alert.alert('Error', 'Enter the 6-digit code'); return; }
    setLoading(true);
    try {
      const { data } = await getApiClient().post('/api/v1/auth/otp/verify', { email, code });
      login(data.accessToken, data.refreshToken, data.user);
      router.replace('/(tabs)');
    } catch (err: any) {
      Alert.alert('Error', err.response?.data?.error ?? 'Invalid code');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={{ flex: 1, backgroundColor: '#f8fafc' }}>
      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : 'height'} style={{ flex: 1, justifyContent: 'center', padding: 24 }}>
        <View style={{ alignItems: 'center', marginBottom: 32 }}>
          <Text style={{ fontSize: 40, marginBottom: 8 }}>🧭</Text>
          <Text style={{ fontSize: 20, fontWeight: '700', color: '#0f172a' }}>
            {step === 'email' ? 'Sign in with OTP' : 'Enter code'}
          </Text>
        </View>

        {step === 'email' ? (
          <View style={{ gap: 16 }}>
            <TextInput
              value={email}
              onChangeText={setEmail}
              placeholder="you@example.com"
              keyboardType="email-address"
              autoCapitalize="none"
              style={{ borderWidth: 1, borderColor: '#e2e8f0', borderRadius: 12, padding: 12, fontSize: 16, backgroundColor: '#fff' }}
            />
            <TouchableOpacity
              onPress={handleSendOtp}
              disabled={loading}
              style={{ backgroundColor: '#0d9488', borderRadius: 12, padding: 14, alignItems: 'center', opacity: loading ? 0.6 : 1 }}
            >
              {loading ? <ActivityIndicator color="#fff" /> : <Text style={{ color: '#fff', fontWeight: '600', fontSize: 16 }}>Send code</Text>}
            </TouchableOpacity>
          </View>
        ) : (
          <View style={{ gap: 16 }}>
            <Text style={{ color: '#64748b', textAlign: 'center' }}>Code sent to {email}</Text>
            <TextInput
              value={code}
              onChangeText={(t) => setCode(t.replace(/\D/g, '').slice(0, 6))}
              placeholder="000000"
              keyboardType="number-pad"
              maxLength={6}
              style={{ borderWidth: 1, borderColor: '#e2e8f0', borderRadius: 12, padding: 14, fontSize: 24, textAlign: 'center', letterSpacing: 8, backgroundColor: '#fff', fontFamily: Platform.OS === 'ios' ? 'Menlo' : 'monospace' }}
            />
            <TouchableOpacity
              onPress={handleVerify}
              disabled={loading || code.length !== 6}
              style={{ backgroundColor: '#0d9488', borderRadius: 12, padding: 14, alignItems: 'center', opacity: loading || code.length !== 6 ? 0.6 : 1 }}
            >
              {loading ? <ActivityIndicator color="#fff" /> : <Text style={{ color: '#fff', fontWeight: '600', fontSize: 16 }}>Verify</Text>}
            </TouchableOpacity>
            <TouchableOpacity onPress={() => setStep('email')} style={{ alignItems: 'center' }}>
              <Text style={{ color: '#64748b' }}>Use different email</Text>
            </TouchableOpacity>
          </View>
        )}

        <View style={{ alignItems: 'center', marginTop: 24 }}>
          <Link href="/(auth)/login">
            <Text style={{ color: '#0d9488', fontWeight: '500' }}>Sign in with password</Text>
          </Link>
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

import { useEffect } from 'react';
import {
  Text,
  View,
  TouchableOpacity,
  ScrollView,
  Image,
} from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useAuthStore } from '../../lib/auth';

export default function ProfileScreen() {
  const router = useRouter();
  const { user, isAuthenticated, isLoading, logout } = useAuthStore();

  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      router.replace('/(auth)/login');
    }
  }, [isLoading, isAuthenticated, router]);

  if (isLoading || !user) {
    return (
      <SafeAreaView style={{ flex: 1, backgroundColor: '#f8fafc', justifyContent: 'center', alignItems: 'center' }}>
        <Text style={{ color: '#64748b' }}>Loading...</Text>
      </SafeAreaView>
    );
  }

  const handleLogout = () => {
    logout();
    router.replace('/(auth)/login');
  };

  return (
    <SafeAreaView style={{ flex: 1, backgroundColor: '#f8fafc' }}>
      <ScrollView contentContainerStyle={{ padding: 24, gap: 24 }}>
        {/* Avatar + Name */}
        <View style={{ alignItems: 'center', gap: 12 }}>
          <View style={{
            width: 80,
            height: 80,
            borderRadius: 40,
            backgroundColor: '#ccfbf1',
            justifyContent: 'center',
            alignItems: 'center',
            overflow: 'hidden',
          }}>
            {user.avatarUrl ? (
              <Image source={{ uri: user.avatarUrl }} style={{ width: 80, height: 80 }} />
            ) : (
              <Text style={{ fontSize: 28, fontWeight: '700', color: '#0d9488' }}>
                {user.username.slice(0, 2).toUpperCase()}
              </Text>
            )}
          </View>
          <Text style={{ fontSize: 20, fontWeight: '700', color: '#0f172a' }}>{user.username}</Text>
          {user.bio && <Text style={{ color: '#64748b', textAlign: 'center' }}>{user.bio}</Text>}
          {user.homeCity && <Text style={{ color: '#94a3b8', fontSize: 13 }}>📍 {user.homeCity}</Text>}
        </View>

        {/* Stats */}
        <View style={{ flexDirection: 'row', justifyContent: 'space-around', paddingVertical: 16, borderTopWidth: 1, borderBottomWidth: 1, borderColor: '#e2e8f0' }}>
          <View style={{ alignItems: 'center' }}>
            <Text style={{ fontSize: 18, fontWeight: '700', color: '#0f172a' }}>{(user as any).followersCount ?? 0}</Text>
            <Text style={{ fontSize: 12, color: '#64748b' }}>Followers</Text>
          </View>
          <View style={{ alignItems: 'center' }}>
            <Text style={{ fontSize: 18, fontWeight: '700', color: '#0f172a' }}>{(user as any).followingCount ?? 0}</Text>
            <Text style={{ fontSize: 12, color: '#64748b' }}>Following</Text>
          </View>
          <View style={{ alignItems: 'center' }}>
            <Text style={{ fontSize: 18, fontWeight: '700', color: '#0f172a' }}>{(user as any).postsCount ?? 0}</Text>
            <Text style={{ fontSize: 12, color: '#64748b' }}>Posts</Text>
          </View>
        </View>

        {/* Interests */}
        {user.interests && user.interests.length > 0 && (
          <View style={{ gap: 8 }}>
            <Text style={{ fontWeight: '600', color: '#374151' }}>Interests</Text>
            <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
              {user.interests.map((interest) => (
                <View key={interest} style={{ backgroundColor: '#ccfbf1', paddingHorizontal: 10, paddingVertical: 4, borderRadius: 12 }}>
                  <Text style={{ color: '#0d9488', fontSize: 12, fontWeight: '500' }}>{interest}</Text>
                </View>
              ))}
            </View>
          </View>
        )}

        {/* Budget */}
        {user.budgetBand && (
          <View style={{ gap: 4 }}>
            <Text style={{ fontWeight: '600', color: '#374151' }}>Budget</Text>
            <Text style={{ color: '#64748b' }}>{user.budgetBand.replace('_', ' ')}</Text>
          </View>
        )}

        {/* Logout */}
        <TouchableOpacity
          onPress={handleLogout}
          style={{
            backgroundColor: '#fee2e2',
            padding: 14,
            borderRadius: 12,
            alignItems: 'center',
            marginTop: 8,
          }}
        >
          <Text style={{ color: '#dc2626', fontWeight: '600' }}>Log out</Text>
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

